INSERT INTO public.courses (id, title, description, price, thumbnail_url, video_url, instructor_id, difficulty, is_active, created_at, updated_at, category, duration_label, mode, audience, curriculum, whatsapp_number, whatsapp_message, provides_certificate, language) VALUES ('f50f8cde-7bdf-467e-a4a8-9d429561ac1f', 'Modern Rice Farming: Boro to Aman', 'Master high-yield paddy cultivation across all three seasons. Covers seed selection, transplanting, water management, IPM and post-harvest handling.', 1500, 'https://images.unsplash.com/photo-1568347877321-f8935c7dc5a8?w=800&auto=format&fit=crop', NULL, NULL, 'beginner', true, '2026-04-18 12:46:08.364352+00', '2026-04-18 12:46:08.364352+00', 'crops', '6 weeks', 'online', 'Rice farmers, smallholders, agriculture students', '[{"title": "Module 1: Land Preparation", "lessons": ["Soil testing basics", "Puddling techniques", "Levelling and bunding"]}, {"title": "Module 2: Seed & Nursery", "lessons": ["Selecting BRRI varieties", "Seed treatment", "Nursery raising"]}, {"title": "Module 3: Transplanting & Spacing", "lessons": ["Plant spacing", "Mat-type seedlings", "Mechanical transplanters"]}, {"title": "Module 4: Water & Fertilizer", "lessons": ["AWD irrigation", "Urea deep placement", "Micronutrient management"]}, {"title": "Module 5: IPM", "lessons": ["Stem borer control", "Brown plant hopper", "Disease scouting"]}, {"title": "Module 6: Harvest & Storage", "lessons": ["Harvest timing", "Drying & milling", "Storage best practices"]}]', '8801712345678', 'Hi, I would like to enroll in Modern Rice Farming course.', true, 'bn');
INSERT INTO public.courses (id, title, description, price, thumbnail_url, video_url, instructor_id, difficulty, is_active, created_at, updated_at, category, duration_label, mode, audience, curriculum, whatsapp_number, whatsapp_message, provides_certificate, language) VALUES ('cb46494b-9e3f-4e7b-a4ef-3f99f67a83ad', 'Hybrid Maize Cultivation for Profit', 'Step-by-step hybrid maize agronomy: from variety choice to silage marketing. Yield 9+ tons/ha.', 1800, 'https://images.unsplash.com/photo-1601593768799-76d3a3eee329?w=800&auto=format&fit=crop', NULL, NULL, 'intermediate', true, '2026-04-18 12:46:08.364352+00', '2026-04-18 12:46:08.364352+00', 'crops', '4 weeks', 'online', 'Commercial maize growers, agro-entrepreneurs', '[{"title": "Module 1: Variety Selection", "lessons": ["Pacific 984 vs NK40", "Seed quality"]}, {"title": "Module 2: Land & Sowing", "lessons": ["Land preparation", "Spacing and depth"]}, {"title": "Module 3: Nutrition", "lessons": ["Basal fertilizer", "Top dressing schedule"]}, {"title": "Module 4: Harvest & Marketing", "lessons": ["Cob maturity signs", "Silage making", "Buyer connections"]}]', '8801712345678', 'Hi, I would like to enroll in Hybrid Maize Cultivation course.', true, 'bn');
INSERT INTO public.courses (id, title, description, price, thumbnail_url, video_url, instructor_id, difficulty, is_active, created_at, updated_at, category, duration_label, mode, audience, curriculum, whatsapp_number, whatsapp_message, provides_certificate, language) VALUES ('23c90ac2-4a42-4100-aceb-84bbeb9f3069', 'Vegetable Gardening: Year-Round Income', 'Plan rotational vegetable plots that earn steady income through every Bangladeshi season.', 1200, 'https://images.unsplash.com/photo-1592924357228-91a4daadcfea?w=800&auto=format&fit=crop', NULL, NULL, 'beginner', true, '2026-04-18 12:46:08.364352+00', '2026-04-18 12:46:08.364352+00', 'crops', '5 weeks', 'online', 'Kitchen gardeners, smallholder farmers, women entrepreneurs', '[{"title": "Module 1: Crop Calendar", "lessons": ["Rabi vs Kharif veg", "Profitable rotations"]}, {"title": "Module 2: Bed Preparation", "lessons": ["Raised beds", "Mulching"]}, {"title": "Module 3: Pest Management", "lessons": ["Yellow sticky traps", "Neem-based sprays"]}, {"title": "Module 4: Harvest & Sales", "lessons": ["Local mandi pricing", "Direct-to-consumer"]}, {"title": "Module 5: Record Keeping", "lessons": ["Cost tracking", "Profit margin"]}]', '8801712345678', 'Hi, I would like to enroll in Vegetable Gardening course.', true, 'bn');
